changeSet.sql:
ALTER TABLE spells
    ADD CONSTRAINT chk_spells_level CHECK (level BETWEEN 0 AND 9);

ALTER TABLE character_class_levels
    ADD CONSTRAINT chk_ccl_class_level CHECK (class_level BETWEEN 1 AND 20);

ALTER TABLE characters
    ADD CONSTRAINT chk_characters_total_level CHECK (total_level BETWEEN 1 AND 20);

ALTER TABLE characters
    ADD CONSTRAINT chk_characters_death_save_successes CHECK (death_save_successes BETWEEN 0 AND 3);

ALTER TABLE characters
    ADD CONSTRAINT chk_characters_death_save_failures CHECK (death_save_failures BETWEEN 0 AND 3);

rollback.sql:
ALTER TABLE spells DROP CONSTRAINT IF EXISTS chk_spells_level;
ALTER TABLE character_class_levels DROP CONSTRAINT IF EXISTS chk_ccl_class_level;
ALTER TABLE characters DROP CONSTRAINT IF EXISTS chk_characters_total_level;
ALTER TABLE characters DROP CONSTRAINT IF EXISTS chk_characters_death_save_successes;
ALTER TABLE characters DROP CONSTRAINT IF EXISTS chk_characters_death_save_failures;
